// Detect anomalies: duplicate invoice numbers, amounts > 3x vendor average,
// payments without matching invoices, unusual patterns
const invoiceItems = $('Read Recent Invoices').all();
const paymentItems = $('Read Recent Payments').all();

const anomalies = [];

// 1. Detect duplicate invoice numbers
const invoiceNumbers = {};
for (const item of invoiceItems) {
  const num = item.json['Invoice Number'] || item.json.Number || '';
  if (!num) continue;
  if (invoiceNumbers[num]) {
    anomalies.push({
      type: 'duplicate_invoice',
      severity: 'High',
      description: `Duplicate invoice number: ${num}`,
      details: {
        invoiceNumber: num,
        occurrences: (invoiceNumbers[num].count || 1) + 1,
        amounts: [...(invoiceNumbers[num].amounts || [invoiceNumbers[num].amount]), parseFloat(item.json.Amount || 0)],
      },
    });
  }
  invoiceNumbers[num] = {
    amount: parseFloat(item.json.Amount || 0),
    count: (invoiceNumbers[num]?.count || 0) + 1,
    amounts: [...(invoiceNumbers[num]?.amounts || []), parseFloat(item.json.Amount || 0)],
  };
}

// 2. Detect amounts > 3x vendor average
const vendorAmounts = {};
for (const item of invoiceItems) {
  const vendor = item.json.Supplier || item.json.Vendor || item.json.Contact || 'Unknown';
  const amount = parseFloat(item.json.Amount || item.json.Total || 0);
  if (!vendorAmounts[vendor]) vendorAmounts[vendor] = [];
  vendorAmounts[vendor].push(amount);
}

for (const [vendor, amounts] of Object.entries(vendorAmounts)) {
  if (amounts.length < 2) continue;
  const avg = amounts.reduce((a, b) => a + b, 0) / amounts.length;
  for (const amount of amounts) {
    if (amount > avg * 3 && amount > 1000) {
      anomalies.push({
        type: 'unusual_amount',
        severity: 'Medium',
        description: `Invoice from ${vendor} is R${amount.toFixed(2)} (${(amount/avg).toFixed(1)}x average of R${avg.toFixed(2)})`,
        details: { vendor, amount, average: avg, ratio: amount / avg },
      });
    }
  }
}

// 3. Detect payments without matching invoices
const invoiceIds = new Set(
  invoiceItems.map(i => i.json['Invoice Number'] || i.json.Number || '').filter(Boolean)
);

for (const item of paymentItems) {
  const ref = item.json['Invoice Reference'] || item.json.Reference || item.json['Invoice Number'] || '';
  if (ref && !invoiceIds.has(ref)) {
    anomalies.push({
      type: 'orphan_payment',
      severity: 'Medium',
      description: `Payment references invoice ${ref} which was not found in recent invoices`,
      details: {
        paymentAmount: parseFloat(item.json.Amount || 0),
        reference: ref,
        paymentDate: item.json.Date || item.json['Payment Date'] || 'Unknown',
      },
    });
  }
}

// 4. Detect unusual patterns (weekend invoices, round numbers)
for (const item of invoiceItems) {
  const date = new Date(item.json.Date || item.json['Invoice Date'] || '');
  const amount = parseFloat(item.json.Amount || 0);
  const dayOfWeek = date.getDay();

  if (dayOfWeek === 0 || dayOfWeek === 6) {
    anomalies.push({
      type: 'weekend_invoice',
      severity: 'Low',
      description: `Invoice created on ${dayOfWeek === 0 ? 'Sunday' : 'Saturday'}: ${item.json['Invoice Number'] || 'N/A'}`,
      details: {
        invoiceNumber: item.json['Invoice Number'] || 'N/A',
        date: date.toISOString().split('T')[0],
        amount,
      },
    });
  }
}

// Summary
const hasAnomalies = anomalies.length > 0;
const highSeverity = anomalies.filter(a => a.severity === 'High').length;
const mediumSeverity = anomalies.filter(a => a.severity === 'Medium').length;
const lowSeverity = anomalies.filter(a => a.severity === 'Low').length;

return {
  json: {
    scanDate: new Date().toISOString().split('T')[0],
    hasAnomalies,
    anomalyCount: anomalies.length,
    highSeverity,
    mediumSeverity,
    lowSeverity,
    anomalies,
    invoicesScanned: invoiceItems.length,
    paymentsScanned: paymentItems.length,
  }
};

